import StarRating from "./Rating/StarRatingByUser";
import TagCard from "./TagCard";

function CourseCard({Text}) {
  return (
    <div className="course-card">
      <img/>
      <div style={{display:"flex", flexDirection:"column", paddingRight:"6rem", position:"relative",flex:"1"}}>
      <h3>NameCourse</h3>
        <span>Description</span>
        <ul>
          <li style={{listStyleType:"none"}}> 
            <TagCard Text={"Web"}/>
          </li>
        </ul>
        <p style={{display:"flex",fontSize:"1.2rem", alignItems:"center"}}>
          <span style={{marginRight:"5px", color:"#FFD700"}}>{courseInfo?.rating}</span>
          <StarRating rating={courseInfo?.rating} SizeStar={16}/> 
        </p>
        <div style={{position:"absolute", insetBlockStart:"0", insetInlineEnd:"0", textAlign:"end"}}>
          <span>Price</span>
        </div>
      </div>
    </div>
  );
}

export default CourseCard;
